
import { defineComponent } from 'vue';
import { mapState, mapMutations } from 'vuex';

interface waveTypesInterface {
  sine: number,
  square: number,
  triangular: number,
  saw: number,
}

export default defineComponent({
  name: 'TheOscillatorController',
  data() {
    return {
      waveType: {
        sine: 0,
        square: 1,
        triangular: 2,
        saw: 3,
      } as waveTypesInterface,
    };
  },
  computed: {
    ...mapState([
      'amplitude',
      'frequency',
      'heightLimit',
      'waveChoice',
      'widthLimit',
    ]),
    amplitudeValue: {
      get(): number {
        return this.amplitude;
      },
      set(value: number) {
        this.updateValue({ key: 'amplitude', value });
      },
    },
    frequencyValue: {
      get(): number {
        return this.frequency;
      },
      set(value: number) {
        this.updateValue({ key: 'frequency', value });
      },
    },
    waveChoiceValue: {
      get(): number {
        return this.waveChoice;
      },
      set(value: number) {
        this.updateValue({ key: 'waveChoice', value });
      },
    },
  },
  methods: {
    ...mapMutations(['updateValue']),
  },
});
